#include<iostream>
using namespace std;
int main()
{
    int h1,h2,a,b,ans=0;
    cin>>h1>>h2>>a>>b;
    if(h2-h1<=a)
    {
        ans=1;
    }
    else if((h2-h1)%(a-b)==0)
    {
        ans=(h2-h1)/(a-b);
    }
    else
    {
        ans=(h2-h1)/(a-b)+1;
    }
    if(ans<0)
    {
        cout<<"-1"<<endl;
    }
    else
    {
        cout<<ans<<endl;
    }

}
